const config = $input.first().json;

const now = new Date();
const dayOfWeek = now.getDay();
const diffToMonday = (dayOfWeek === 0 ? -6 : 1 - dayOfWeek);

const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() + diffToMonday - 7);
lastMonday.setHours(0,0,0,0);

const lastSunday = new Date(lastMonday);
lastSunday.setDate(lastMonday.getDate() + 6);
lastSunday.setHours(23,59,59,999);

const fmt = (d) => d.toISOString().split('T')[0];

const weekLabel = `${fmt(lastMonday)} to ${fmt(lastSunday)}`;

return [{
  json: {
    since: fmt(lastMonday),
    until: fmt(lastSunday),
    week_label: weekLabel,
    data: {
      Facebook_Page_ID: config.Facebook_Page_ID,
      IG_Business_Account_ID: config.IG_Business_Account_ID,
      Meta_Access_Token: config.Meta_Access_Token,
      Facebook_Page_Access_Token: config.Facebook_Page_Access_Token,
      Report_Email: config.Report_Email
    }
  }
}];

const fbData = $node["Get Facebook Feed"].json.data || [];
const fbInsights = $node["Get Facebook Page Insights"].json.data || [];
const fbContentViews = $node["Get Facebook Content Views"].json.data[0]?.values || [];

const postsArray = [];
const metrics = {};

fbData.forEach(post => {
  postsArray.push({
    post_id: post.id,
    message: post.message || "",
    created_time: post.created_time,
    permalink: post.permalink_url || "",
    thumbnail: post.full_picture || "",
    likes_count: post.likes?.summary?.total_count || 0,
    comments_count: post.comments?.summary?.total_count || 0
  });
});

fbInsights.forEach(item => {
  const name = item.name;
  metrics[name] = item.values.map(v => ({ value: v.value, end_time: v.end_time }));
});

const organicViews = fbContentViews
  .filter(v => v.is_from_ads === "0")
  .map(v => ({ value: v.value, end_time: v.end_time }));

metrics["page_media_view"] = organicViews;

const totalViews = (metrics.page_views_total || []).reduce((s, v) => s + (v.value || 0), 0);
const totalEngagements = (metrics.page_post_engagements || []).reduce((s, v) => s + (v.value || 0), 0);
const totalMediaViews = organicViews.reduce((s, v) => s + (v.value || 0), 0);

return [{
  json: {
    data: {
      feed: postsArray,
      insights: metrics,
      summary: {
        total_views: totalViews,
        total_engagements: totalEngagements,
        total_media_views: totalMediaViews,
        total_posts: postsArray.length
      }
    }
  }
}];

const accessToken = $node["Calculate Dates and Wrap Data"].json.data.Meta_Access_Token;
const igId = $node["Calculate Dates and Wrap Data"].json.data.IG_Business_Account_ID;
const metrics = 'profile_views,reach,accounts_engaged,total_interactions';

const sinceDate = new Date($node["Calculate Dates and Wrap Data"].json.since);
const untilDate = new Date($node["Calculate Dates and Wrap Data"].json.until);

function toUnix(date) { return Math.floor(date.getTime() / 1000); }

const results = [];
let currentDate = new Date(sinceDate);

while (currentDate <= untilDate) {
  const since = toUnix(currentDate);
  const nextDay = new Date(currentDate);
  nextDay.setDate(nextDay.getDate() + 1);
  const until = toUnix(nextDay);

  const url = `https://graph.facebook.com/v23.0/${igId}/insights`;
  const qs = { metric: metrics, metric_type: 'total_value', period: 'day', since, until, access_token: accessToken };

  try {
    const response = await this.helpers.request({ method: 'GET', uri: url, qs, json: true });
    const cleanObj = { date: currentDate.toISOString().split('T')[0] };
    if (response.data && Array.isArray(response.data)) {
      response.data.forEach(metric => {
        cleanObj[metric.name] = metric.total_value?.value ?? 0;
      });
    }
    results.push(cleanObj);
  } catch (error) {
    results.push({ date: currentDate.toISOString().split('T')[0], error: error.message });
  }

  currentDate.setDate(currentDate.getDate() + 1);
}

return [{ data: results }];

const accessToken = $node["Calculate Dates and Wrap Data"].json.data.Meta_Access_Token;
const igId = $node["Calculate Dates and Wrap Data"].json.data.IG_Business_Account_ID;

const sinceDate = new Date($node["Calculate Dates and Wrap Data"].json.since);
const untilDate = new Date($node["Calculate Dates and Wrap Data"].json.until);

function toUnix(date) { return Math.floor(date.getTime() / 1000); }

const results = [];
let currentDate = new Date(sinceDate);

while (currentDate <= untilDate) {
  const since = toUnix(currentDate);
  const nextDay = new Date(currentDate);
  nextDay.setDate(nextDay.getDate() + 1);
  const until = toUnix(nextDay);

  const url = `https://graph.facebook.com/v23.0/${igId}/insights`;
  const qs = { metric: 'follows_and_unfollows', metric_type: 'total_value', period: 'day', breakdown: 'follow_type', since, until, access_token: accessToken };

  try {
    const response = await this.helpers.request({ method: 'GET', uri: url, qs, json: true });
    const breakdowns = response.data[0]?.total_value?.breakdowns?.[0]?.results || [];
    const formatted = { date: currentDate.toISOString().split('T')[0] };
    breakdowns.forEach(item => { formatted[item.dimension_values[0]] = item.value; });
    results.push(formatted);
  } catch (error) {
    results.push({ date: currentDate.toISOString().split('T')[0], error: error.message });
  }

  currentDate.setDate(currentDate.getDate() + 1);
}

return [{ data: results }];

const insightsData = $node["Get Instagram Insights"].json?.data || [];
const activityData = $node["Get Instagram Activity"].json;
const followData = $node["Get Instagram Follows and Unfollows"].json?.data || [];
const viewsData = $node["Views"].json?.data || [];

const viewsBreakdown = viewsData?.[0]?.total_value?.breakdowns?.[0]?.results || [];
const organicViews = viewsBreakdown
  .filter(item => item.dimension_values[0] !== "AD")
  .map(item => ({ category: item.dimension_values[0], views: item.value }));
const totalOrganicViews = organicViews.reduce((acc, item) => acc + item.views, 0);

const postsArray = (activityData.data || []).reduce((acc, post) => {
  if (!post.timestamp) return acc;
  const structuredMedia = [];
  if (post.media_url) {
    structuredMedia.push({
      id: post.id, type: post.media_type || "IMAGE",
      url: post.media_url, thumbnail_url: post.thumbnail_url || null, caption: post.caption || null
    });
  }
  acc.push({
    id: post.id, caption: post.caption || null, permalink: post.permalink || null,
    timestamp: post.timestamp, username: post.username || null,
    like_count: post.like_count ?? 0, comments_count: post.comments_count ?? 0, media: structuredMedia
  });
  return acc;
}, []);

const allDates = new Set();
[...insightsData, ...followData].forEach(item => allDates.add(item.date));

const metrics = {};
insightsData.forEach(metric => {
  metrics[metric.date] = {
    profile_views: metric.profile_views ?? 0,
    accounts_engaged: metric.accounts_engaged ?? 0,
    total_interactions: metric.total_interactions ?? 0,
    reach: metric.reach ?? 0
  };
});
followData.forEach(f => {
  if (!metrics[f.date]) metrics[f.date] = {};
  metrics[f.date]["new_followers"] = f.FOLLOWER ?? 0;
  metrics[f.date]["non_followers"] = f.NON_FOLLOWER ?? 0;
});
allDates.forEach(date => {
  if (!metrics[date]) metrics[date] = { profile_views:0, accounts_engaged:0, total_interactions:0, new_followers:0, non_followers:0, reach:0 };
  else {
    metrics[date]["new_followers"] = metrics[date]["new_followers"] ?? 0;
    metrics[date]["non_followers"] = metrics[date]["non_followers"] ?? 0;
    metrics[date]["profile_views"] = metrics[date]["profile_views"] ?? 0;
    metrics[date]["accounts_engaged"] = metrics[date]["accounts_engaged"] ?? 0;
    metrics[date]["total_interactions"] = metrics[date]["total_interactions"] ?? 0;
    metrics[date]["reach"] = metrics[date]["reach"] ?? 0;
  }
});

const finalMetrics = Array.from(allDates).sort().map(date => ({ date, ...metrics[date] }));

const igSummary = {
  total_profile_views: finalMetrics.reduce((s,d) => s+(d.profile_views||0),0),
  total_reach: finalMetrics.reduce((s,d) => s+(d.reach||0),0),
  total_accounts_engaged: finalMetrics.reduce((s,d) => s+(d.accounts_engaged||0),0),
  total_interactions: finalMetrics.reduce((s,d) => s+(d.total_interactions||0),0),
  total_new_followers: finalMetrics.reduce((s,d) => s+(d.new_followers||0),0)
};

return [{ json: { data: {
  activity: postsArray,
  insights: finalMetrics,
  views: { total: totalOrganicViews, breakdown: organicViews },
  summary: igSummary
}}}];

const fbData = $node["Organize Facebook Data"].json.data;
