function chartUrl(config, width, height) {
  let url = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(config))}`;
  if (width && height) url += `&width=${width}&height=${height}`;
  return url;
}

function generateLineChart(labels, data, label, title, color) {
  return {
    type: "line",
    data: { labels, datasets: [{ label, data, borderColor: color, backgroundColor: color + '22', fill: true, tension: 0.4, pointRadius: 4 }] },
    options: { responsive: true, plugins: { title: { display: true, text: title, font: { size: 16 } }, legend: { display: false } }, scales: { y: { beginAtZero: true } } }
  };
}

// Instagram chart data
const igDates = igData.insights.map(d => d.date.slice(5));
const igReach = igData.insights.map(d => d.reach);
const igEngaged = igData.insights.map(d => d.accounts_engaged);
const igFollowers = igData.insights.map(d => d.new_followers);

// Facebook chart data
const fbViews = fbData.insights.page_views_total || [];
const fbEngagements = fbData.insights.page_post_engagements || [];
const fbDates = fbViews.map(v => v.end_time?.slice(5,10) || '');
const fbViewsData = fbViews.map(v => v.value || 0);
const fbEngData = fbEngagements.map(v => v.value || 0);

// Chart URLs
const igReachChartUrl = chartUrl(generateLineChart(igDates, igReach, 'Reach', 'Instagram Weekly Reach', '#E1306C'), 700, 300);
const igEngChartUrl = chartUrl(generateLineChart(igDates, igEngaged, 'Accounts Engaged', 'Instagram Accounts Engaged', '#833AB4'), 700, 300);
const igFollowChartUrl = chartUrl(generateLineChart(igDates, igFollowers, 'New Followers', 'Instagram New Followers', '#F77737'), 700, 300);
const fbViewsChartUrl = chartUrl(generateLineChart(fbDates, fbViewsData, 'Page Views', 'Facebook Page Views', '#1877F2'), 700, 300);
const fbEngChartUrl = chartUrl(generateLineChart(fbDates, fbEngData, 'Post Engagements', 'Facebook Post Engagements', '#42B72A'), 700, 300);

return [{ json: { weekLabel, since, until,
  fbData, igData,
  charts: { igReachChartUrl, igEngChartUrl, igFollowChartUrl, fbViewsChartUrl, fbEngChartUrl }
