  .post-meta { font-size:11px; color:#9ca3af; margin-bottom:6px; }
  .post-text { font-size:13px; line-height:1.6; color:#374151; margin-bottom:10px; }
  .post-stats { display:flex; flex-wrap:wrap; gap:8px; }
  .pstat { font-size:12px; color:#6b7280; background:#f3f4f6; padding:3px 8px; border-radius:6px; }
  .pstat-link { color:#e94560; background:#fff5f7; text-decoration:none; }

  /* ── Next Steps ── */
  .next-steps { display:grid; grid-template-columns:1fr 1fr; gap:12px; margin-top:16px; }
  .step-card { background:linear-gradient(135deg,#fff5f7,#fff); border:1px solid #fecdd3; border-radius:12px; padding:20px; break-inside:avoid; }
  .step-num { width:28px; height:28px; background:#e94560; color:#fff; border-radius:50%; display:flex; align-items:center; justify-content:center; font-size:13px; font-weight:700; margin-bottom:10px; }
  .step-text { font-size:13px; line-height:1.6; color:#374151; }

  /* ── Footer ── */
  .footer { background:#1a1a2e; color:rgba(255,255,255,0.4); text-align:center; padding:24px; font-size:12px; break-inside:avoid; }
  .footer strong { color:#e94560; }

  /* ── Section page breaks ── */
  .section-break { break-before:auto; }
</style>
</head>
