<div class="page">

  <!-- HEADER -->
  <div class="header">
    <div class="header-top">
      <span class="brand">Social Media Analytics</span>
      <span class="report-badge">Weekly Report</span>
    </div>
    <h1>Performance Report</h1>
    <p class="week">Week of ${esc(weekLabel)}</p>
    <div class="header-stats">
      <div class="hstat"><div class="hstat-val">${fb.summary.total_views.toLocaleString()}</div><div class="hstat-label">FB Page Views</div></div>
      <div class="hstat"><div class="hstat-val">${fb.summary.total_engagements.toLocaleString()}</div><div class="hstat-label">FB Engagements</div></div>
