      <div class="combined-card"><div class="combined-val">${combinedFollowers}</div><div class="combined-label">New Followers</div><div class="combined-sub">Instagram Growth</div></div>
    </div>
  </div>

  <!-- AI EXECUTIVE SUMMARY -->
  <div class="section section-break">
    <div class="section-title">AI-Powered Analysis</div>
    <div class="ai-section">
      <span class="ai-badge">🤖 Executive Summary</span>
      <p class="ai-text">${esc(execSummary)}</p>
    </div>
  </div>

  <!-- FACEBOOK -->
  <div class="section section-break">
    <div class="platform-header">
      <div class="platform-icon fb-icon">f</div>
      <span class="platform-name">Facebook Performance</span>
    </div>
    <div class="stats-grid">
      <div class="stat-card"><div class="stat-val">${fb.summary.total_views.toLocaleString()}</div><div class="stat-label">Page Views</div></div>
      <div class="stat-card"><div class="stat-val">${fb.summary.total_engagements.toLocaleString()}</div><div class="stat-label">Engagements</div></div>
      <div class="stat-card"><div class="stat-val">${fb.summary.total_media_views.toLocaleString()}</div><div class="stat-label">Media Views</div></div>
      <div class="stat-card"><div class="stat-val">${fb.summary.total_posts}</div><div class="stat-label">Posts Published</div></div>
    </div>
    <div class="chart-row">
      <div class="chart-box"><div class="chart-title">Page Views (Daily)</div><img src="${charts.fbViewsChartUrl}" alt="FB Views"/></div>
      <div class="chart-box"><div class="chart-title">Post Engagements (Daily)</div><img src="${charts.fbEngChartUrl}" alt="FB Engagements"/></div>
    </div>
    <div class="ai-section">
      <span class="ai-badge">📊 Facebook Insights</span>
      <p class="ai-text">${esc(fbAnalysis)}</p>
    </div>
    <div class="section-title" style="margin-top:8px;">Posts Published This Week</div>
    <div class="posts-grid">${fbPostsHtml}</div>
  </div>

  <!-- INSTAGRAM -->
  <div class="section section-break">
    <div class="platform-header">
      <div class="platform-icon ig-icon">📸</div>
      <span class="platform-name">Instagram Performance</span>
    </div>
    <div class="stats-grid">
      <div class="stat-card"><div class="stat-val">${ig.summary.total_reach.toLocaleString()}</div><div class="stat-label">Total Reach</div></div>
      <div class="stat-card"><div class="stat-val">${ig.summary.total_accounts_engaged.toLocaleString()}</div><div class="stat-label">Accounts Engaged</div></div>
      <div class="stat-card"><div class="stat-val">${ig.summary.total_interactions.toLocaleString()}</div><div class="stat-label">Interactions</div></div>
      <div class="stat-card"><div class="stat-val">${ig.summary.total_new_followers}</div><div class="stat-label">New Followers</div></div>
    </div>
    <div class="chart-row">
      <div class="chart-box"><div class="chart-title">Instagram Reach (Daily)</div><img src="${charts.igReachChartUrl}" alt="IG Reach"/></div>
      <div class="chart-box"><div class="chart-title">Accounts Engaged (Daily)</div><img src="${charts.igEngChartUrl}" alt="IG Engaged"/></div>
