    <div class="chart-row">
      <div class="chart-box" style="grid-column:1/-1;"><div class="chart-title">New Followers (Daily)</div><img src="${charts.igFollowChartUrl}" alt="IG Followers"/></div>
    </div>
    <div class="ai-section">
      <span class="ai-badge">📱 Instagram Insights</span>
      <p class="ai-text">${esc(igAnalysis)}</p>
    </div>
    <div class="section-title" style="margin-top:8px;">Posts Published This Week</div>
    <div class="posts-grid">${igPostsHtml}</div>
  </div>

  <!-- CROSS PLATFORM -->
  <div class="section section-break">
    <div class="section-title">Cross-Platform Analysis</div>
    <div class="ai-section">
      <span class="ai-badge">🔗 Combined Insights</span>
      <p class="ai-text">${esc(crossInsights)}</p>
    </div>
  </div>

  <!-- NEXT STEPS -->
  <div class="section section-break">
    <div class="section-title">Action Plan</div>
    <h2>Next Steps</h2>
    <div class="next-steps" style="margin-top:16px;">${nextStepCardsHtml}</div>
  </div>

  <!-- FOOTER -->
  <div class="footer">
    Generated automatically by <strong>Social Media Analytics Workflow</strong> &bull; Week of ${esc(weekLabel)}
  </div>

</div>
</body>
</html>`;

